import json
import base64
import os
import time
from urllib.parse import urlparse

import requests


DEFAULT_TIMEOUT_SECONDS = float(os.getenv("ENRICH_TIMEOUT_SECONDS", "0.5"))
MAX_URLS = int(os.getenv("ENRICH_MAX_URLS", "5"))
MAX_BODY_BYTES = int(os.getenv("ENRICH_MAX_BODY_BYTES", "8192"))
MAX_TOTAL_BYTES = int(os.getenv("ENRICH_MAX_TOTAL_BYTES", "24576"))
ALLOW_PRIVATE_IPS = os.getenv("ENRICH_ALLOW_PRIVATE_IPS", "false").lower() == "true"
ALLOWED_SCHEMES = {"http", "https"}
ALLOWED_HOST_SUFFIXES = [
    s.strip().lower()
    for s in os.getenv("ENRICH_ALLOWED_HOST_SUFFIXES", "").split(",")
    if s.strip()
]
USER_AGENT = os.getenv("ENRICH_USER_AGENT", "edge-enricher/1.0")
HEADER_URL_KEYS = [s.strip().lower() for s in os.getenv("ENRICH_HEADER_KEYS", "x-enrich-url").split(",") if s.strip()]
OUT_HEADER_PREFIX = os.getenv("ENRICH_OUT_HEADER_PREFIX", "x-enrich-")


def _cf_get_header(request, name_lc):
    hdrs = request.get("headers", {})
    vals = hdrs.get(name_lc)
    if not vals:
        return None
    v = vals[0].get("value")
    return v


def _cf_set_header(request, name_lc, value):
    request.setdefault("headers", {})
    request["headers"][name_lc] = [{"key": name_lc, "value": value}]


def _cf_del_header(request, name_lc):
    hdrs = request.get("headers", {})
    if name_lc in hdrs:
        del hdrs[name_lc]


def _is_ip_private(hostname):
    import ipaddress
    try:
        ip = ipaddress.ip_address(hostname)
        return ip.is_private or ip.is_loopback or ip.is_link_local or ip.is_reserved or ip.is_multicast
    except Exception:
        return False


def _dns_resolves_to_private(hostname):
    import socket
    import ipaddress
    try:
        infos = socket.getaddrinfo(hostname, None)
        for info in infos:
            addr = info[4][0]
            try:
                ip = ipaddress.ip_address(addr)
                if ip.is_private or ip.is_loopback or ip.is_link_local or ip.is_reserved or ip.is_multicast:
                    return True
            except Exception:
                continue
    except Exception:
        return False
    return False


def _host_allowed(hostname):
    if not hostname:
        return False
    h = hostname.lower().strip(".")
    if _is_ip_private(h):
        return ALLOW_PRIVATE_IPS
    if not ALLOW_PRIVATE_IPS and _dns_resolves_to_private(h):
        return False
    if not ALLOWED_HOST_SUFFIXES:
        return True
    for suf in ALLOWED_HOST_SUFFIXES:
        suf = suf.lstrip(".")
        if h == suf or h.endswith("." + suf):
            return True
    return False


def _parse_urls(raw):
    if not raw:
        return []
    raw = raw.strip()
    if not raw:
        return []
    urls = []
    parts = []
    if "\n" in raw or "\r" in raw:
        parts = [p.strip() for p in raw.replace("\r", "\n").split("\n")]
    elif "," in raw:
        parts = [p.strip() for p in raw.split(",")]
    else:
        parts = [raw]
    for p in parts:
        if not p:
            continue
        urls.append(p)
    return urls[:MAX_URLS]


def _safe_fetch(url, timeout_seconds):
    parsed = urlparse(url)
    if parsed.scheme.lower() not in ALLOWED_SCHEMES:
        return {"url": url, "ok": False, "error": "scheme_not_allowed"}
    if not _host_allowed(parsed.hostname):
        return {"url": url, "ok": False, "error": "host_not_allowed"}

    headers = {
        "User-Agent": USER_AGENT,
        "Accept": "application/json, text/plain;q=0.9, */*;q=0.1",
    }
    try:
        resp = requests.get(url, headers=headers, timeout=timeout_seconds, allow_redirects=False)
        status = resp.status_code
        content_type = resp.headers.get("Content-Type", "")
        content = resp.content or b""
        if len(content) > MAX_BODY_BYTES:
            content = content[:MAX_BODY_BYTES]
        body_b64 = base64.b64encode(content).decode("ascii") if content else ""
        return {
            "url": url,
            "ok": True,
            "status": status,
            "content_type": content_type,
            "body_b64": body_b64,
        }
    except Exception as e:
        return {"url": url, "ok": False, "error": str(e)}


def handler(event, context):
    record = event["Records"][0]
    cf = record["cf"]
    request = cf["request"]

    urls = []
    for k in HEADER_URL_KEYS:
        v = _cf_get_header(request, k)
        if v:
            urls.extend(_parse_urls(v))

    urls = urls[:MAX_URLS]

    # Prevent forwarding the enrich URL headers to origin by default
    if os.getenv("ENRICH_FORWARD_URL_HEADERS", "false").lower() != "true":
        for k in HEADER_URL_KEYS:
            _cf_del_header(request, k)

    if not urls:
        return request

    started = time.time()
    results = []
    total_bytes = 0

    for url in urls:
        if (time.time() - started) > (DEFAULT_TIMEOUT_SECONDS * 4):
            results.append({"url": url, "ok": False, "error": "time_budget_exceeded"})
            continue

        r = _safe_fetch(url, DEFAULT_TIMEOUT_SECONDS)
        results.append(r)

        body_b64 = r.get("body_b64") or ""
        if body_b64:
            total_bytes += len(body_b64)
            if total_bytes > MAX_TOTAL_BYTES:
                r["body_b64"] = ""
                r["truncated"] = True

    payload = {
        "v": 1,
        "count": len(results),
        "results": results,
    }

    out_json = json.dumps(payload, separators=(",", ":"), ensure_ascii=False)
    out_b64 = base64.b64encode(out_json.encode("utf-8")).decode("ascii")

    _cf_set_header(request, (OUT_HEADER_PREFIX + "context").lower(), out_b64)
    _cf_set_header(request, (OUT_HEADER_PREFIX + "count").lower(), str(len(results)))

    return request